import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { Zap, Eye, EyeOff, ArrowRight, Loader2 } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { ErrorAlert, FormField } from '../components/UI';
import toast from 'react-hot-toast';

// ─── Shared Auth Layout ────────────────────────────────────
const AuthLayout = ({ children, title, subtitle }) => (
  <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4 relative overflow-hidden">
    {/* Background decoration */}
    <div className="absolute inset-0 overflow-hidden pointer-events-none">
      <div className="absolute -top-40 -right-40 w-96 h-96 bg-brand-600/10 rounded-full blur-3xl" />
      <div className="absolute -bottom-40 -left-40 w-96 h-96 bg-indigo-600/10 rounded-full blur-3xl" />
    </div>

    <div className="relative w-full max-w-md animate-slide-up">
      {/* Logo */}
      <div className="flex items-center gap-3 mb-8">
        <div className="w-10 h-10 rounded-xl bg-brand-600 flex items-center justify-center">
          <Zap className="w-5 h-5 text-white" />
        </div>
        <div>
          <h1 className="text-base font-bold text-slate-100">MyMicroservices</h1>
          <p className="text-xs text-slate-500">Admin Panel</p>
        </div>
      </div>

      <div className="glass rounded-2xl p-8">
        <h2 className="text-2xl font-bold text-slate-100 mb-1">{title}</h2>
        <p className="text-slate-500 mb-8">{subtitle}</p>
        {children}
      </div>
    </div>
  </div>
);

// ═══════════════════════════════════════════════════════════
// LOGIN PAGE
// ═══════════════════════════════════════════════════════════
export const LoginPage = () => {
  const [form, setForm]       = useState({ email: '', password: '' });
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState('');
  const { login }             = useAuth();
  const navigate              = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      await login(form.email, form.password);
      toast.success('Đăng nhập thành công!');
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Email hoặc mật khẩu không đúng!');
    } finally {
      setLoading(false);
    }
  };

  return (
    <AuthLayout title="Chào mừng trở lại" subtitle="Đăng nhập để tiếp tục quản lý hệ thống">
      <form onSubmit={handleSubmit} className="space-y-5">
        {error && <ErrorAlert message={error} onClose={() => setError('')} />}

        <FormField label="Email" required>
          <input
            type="email"
            className="input-field"
            placeholder="admin@example.com"
            value={form.email}
            onChange={e => setForm(f => ({ ...f, email: e.target.value }))}
            required
          />
        </FormField>

        <FormField label="Mật khẩu" required>
          <div className="relative">
            <input
              type={showPass ? 'text' : 'password'}
              className="input-field pr-11"
              placeholder="••••••••"
              value={form.password}
              onChange={e => setForm(f => ({ ...f, password: e.target.value }))}
              required
            />
            <button
              type="button"
              onClick={() => setShowPass(p => !p)}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-slate-300"
            >
              {showPass ? <EyeOff size={18} /> : <Eye size={18} />}
            </button>
          </div>
        </FormField>

        <button type="submit" disabled={loading} className="btn-primary w-full justify-center mt-2">
          {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <ArrowRight size={18} />}
          {loading ? 'Đang đăng nhập...' : 'Đăng nhập'}
        </button>

        <p className="text-center text-sm text-slate-500">
          Chưa có tài khoản?{' '}
          <Link to="/register" className="text-brand-400 hover:text-brand-300 font-medium">
            Đăng ký ngay
          </Link>
        </p>
      </form>
    </AuthLayout>
  );
};

// ═══════════════════════════════════════════════════════════
// REGISTER PAGE
// ═══════════════════════════════════════════════════════════
export const RegisterPage = () => {
  const [form, setForm]       = useState({ name: '', email: '', password: '' });
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState('');
  const { register }          = useAuth();
  const navigate              = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    if (form.password.length < 6) {
      setError('Mật khẩu phải ít nhất 6 ký tự!');
      return;
    }
    setLoading(true);
    try {
      await register(form.name, form.email, form.password);
      toast.success('Đăng ký thành công! Vui lòng đăng nhập.');
      navigate('/login');
    } catch (err) {
      setError(err.response?.data?.message || 'Đăng ký thất bại!');
    } finally {
      setLoading(false);
    }
  };

  return (
    <AuthLayout title="Tạo tài khoản" subtitle="Điền thông tin để đăng ký tài khoản mới">
      <form onSubmit={handleSubmit} className="space-y-5">
        {error && <ErrorAlert message={error} onClose={() => setError('')} />}

        <FormField label="Họ tên" required>
          <input
            type="text"
            className="input-field"
            placeholder="Nguyễn Văn A"
            value={form.name}
            onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
            required
          />
        </FormField>

        <FormField label="Email" required>
          <input
            type="email"
            className="input-field"
            placeholder="admin@example.com"
            value={form.email}
            onChange={e => setForm(f => ({ ...f, email: e.target.value }))}
            required
          />
        </FormField>

        <FormField label="Mật khẩu" required>
          <div className="relative">
            <input
              type={showPass ? 'text' : 'password'}
              className="input-field pr-11"
              placeholder="Ít nhất 6 ký tự"
              value={form.password}
              onChange={e => setForm(f => ({ ...f, password: e.target.value }))}
              required
            />
            <button
              type="button"
              onClick={() => setShowPass(p => !p)}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-slate-300"
            >
              {showPass ? <EyeOff size={18} /> : <Eye size={18} />}
            </button>
          </div>
        </FormField>

        <button type="submit" disabled={loading} className="btn-primary w-full justify-center mt-2">
          {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <ArrowRight size={18} />}
          {loading ? 'Đang đăng ký...' : 'Tạo tài khoản'}
        </button>

        <p className="text-center text-sm text-slate-500">
          Đã có tài khoản?{' '}
          <Link to="/login" className="text-brand-400 hover:text-brand-300 font-medium">
            Đăng nhập
          </Link>
        </p>
      </form>
    </AuthLayout>
  );
};
